{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Schedule of Activities (SOA) Schema",
  "description": "JSON schema for extracting Schedule of Activities from clinical trial PDFs",
  "type": "object",
  "properties": {
    "schedule_of_activities": {
      "type": "array",
      "description": "Array of SOA entries representing each meeting/visit",
      "items": {
        "type": "object",
        "properties": {
          "meeting_number": {
            "type": "integer",
            "description": "Sequential meeting/visit identifier",
            "minimum": 1,
            "examples": [1, 2, 3, 4, 5]
          },
          "meeting_name": {
            "type": "string",
            "description": "Descriptive name of the visit/meeting phase",
            "minLength": 1,
            "examples": [
              "Screening",
              "Intervention Period",
              "Baseline",
              "Follow-up",
              "End of Study"
            ]
          },
          "actions_to_perform": {
            "type": "array",
            "description": "List of individual procedures, assessments, or activities to be performed",
            "items": {
              "type":"string",
              "minLength": 1
            },
            "minLength": 1,
            "examples": [
              "Informed consent, Inclusion and exclusion",
              "Inclusion and exclusion criteria, Nasal endoscopy",
              "Smoking status, IRT, Vital signs"]
          },
          "days_since_first_meeting": {
            "type": "integer",
            "description": "Number of days since the first meeting (negative values for pre-study activities)",
            "examples": [-28, 1, 15, 29, 43]
          },
          "visit_type": {
            "type": "string",
            "description": "Type or frequency classification of the visit",
            "minLength": 1,
            "examples": [
              "Weekly (שבוע)",
              "Monthly",
              "Bi-weekly",
              "Quarterly",
              "As needed"
            ]
          },
          "allowed_deviation": {
            "type": "integer",
            "description": "Permitted timing deviation in days",
            "minimum": 0,
            "examples": [0, 1, 2, 3, 7]
          }
        },
        "required": [
          "meeting_number",
          "meeting_name",
          "actions_to_perform",
          "days_since_first_meeting",
          "visit_type",
          "allowed_deviation"
        ],
        "additionalProperties": false
      },
      "minItems": 1
    },
    "metadata": {
      "type": "object",
      "description": "Optional metadata about the extraction",
      "properties": {
        "extraction_date": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp of when the extraction was performed"
        },
        "source_document": {
          "type": "string",
          "description": "Name or identifier of the source PDF document"
        },
        "total_meetings": {
          "type": "integer",
          "description": "Total number of meetings/visits extracted",
          "minimum": 1
        },
        "study_duration_days": {
          "type": "integer",
          "description": "Total study duration from first to last meeting in days"
        },
        "extraction_notes": {
          "type": "array",
          "description": "Any notes or observations from the extraction process",
          "items": {
            "type": "string"
          }
        }
      },
      "additionalProperties": false
    }
  },
  "required": ["schedule_of_activities"],
  "additionalProperties": false,
  "examples": [
    {
      "schedule_of_activities": [
        {
          "meeting_number": 1,
          "meeting_name": "Screening",
          "actions_to_perform": ["Informed consent", "Inclusion and exclusion"],
          "days_since_first_meeting": -28,
          "visit_type": "Weekly (שבוע)",
          "allowed_deviation": 0
        },
        {
          "meeting_number": 2,
          "meeting_name": "Intervention Period",
          "actions_to_perform": ["Inclusion and exclusion criteria", "Nasal endoscopy"],
          "days_since_first_meeting": 1,
          "visit_type": "Weekly (שבוע)",
          "allowed_deviation": 0
        },
        {
          "meeting_number": 3,
          "meeting_name": "Intervention Period",
          "actions_to_perform": ["Smoking status", "IRT", "Vital signs"],
          "days_since_first_meeting": 15,
          "visit_type": "Weekly (שבוע)",
          "allowed_deviation": 0
        },
        {
          "meeting_number": 4,
          "meeting_name": "Intervention Period",
          "actions_to_perform": ["Record planned endoscopic sinus surgery", "PI"],
          "days_since_first_meeting": 29,
          "visit_type": "Weekly (שבוע)",
          "allowed_deviation": 0
        },
        {
          "meeting_number": 5,
          "meeting_name": "Intervention Period",
          "actions_to_perform": ["IMP administration", "AxMP dispensation", "Symptom review"],
          "days_since_first_meeting": 43,
          "visit_type": "Weekly (שבוע)",
          "allowed_deviation": 0
        }
      ],
      "metadata": {
        "extraction_date": "2025-05-29T10:00:00Z",
        "source_document": "clinical_trial_protocol_v1.2.pdf",
        "total_meetings": 5,
        "study_duration_days": 71,
        "extraction_notes": [
          "All meetings extracted successfully",
          "Hebrew text preserved in visit_type field"
        ]
      }
    }
  ]
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Clinical Trial Data",
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "output": {
        "type": "object",
        "properties": {
          "distinct_actions": {
            "type": "array",
            "items": {
              "type": "string",
              "minLength": 1
            },
            "uniqueItems": true,
            "minItems": 1,
            "description": "Array of unique clinical trial actions, procedures, and assessments"
          },
          "total_count": {
            "type": "integer",
            "minimum": 0,
            "description": "Total count of distinct actions"
          }
        },
        "required": ["distinct_actions", "total_count"],
        "additionalProperties": false
      }
    },
    "required": ["output"],
    "additionalProperties": false
  }
}

parameters.jsCode:
return [
  {
    json: {
      output:{
      data:{ 
        schedule_of_activities: $('Schedule of Activities').first().json.output.schedule_of_activities ,
        metadata: {
          start_page: $('Map Pages').first().json['Start Page'],
          end_page:$('Map Pages').first().json['End Page'] ,
      researchid:$('Webhook').first().json.body.researchId ,
        siteid: $('Webhook').first().json.body.siteId,
          activities: $('Reorder activities').first().json.output[0].output.distinct_actions
        }
      }
      }
    }
  }
];

// n8n JavaScript Code node
// Extract distinct actions_to_perform from output.schedule_of_activities

const scheduleOfActivities =
  $input.first().json?.output?.schedule_of_activities ?? [];

// Collect all actions from all meetings
const allActions = scheduleOfActivities.flatMap((meeting) => {
  const actions = meeting?.actions_to_perform;

  // Ensure we always return an array
  if (Array.isArray(actions)) return actions;
  if (typeof actions === "string" && actions.trim()) return [actions.trim()];
  return [];
});

// Deduplicate + sort
const distinctActions = [...new Set(allActions)]
  .filter((x) => typeof x === "string" && x.trim())
  .map((x) => x.trim())
  .sort((a, b) => a.localeCompare(b));

// Return single item with output object
return [
  {
    json: {
      output: {
        distinct_actions: distinctActions,
        total_count: distinctActions.length,
      },
    },
  },
];

